import React, { Component } from 'react'
import { Container, TextField, Button, Card, CardContent, Typography } from '@material-ui/core'

import { connect } from 'react-redux'
import { getUserRepos } from '../src/_actions/Repos'



class App extends Component {
  constructor() {
    super()
    this.state = { 
      result: ''
    }
    this.handleSearch = this.handleSearch.bind(this)
    this.handleInput = this.handleInput.bind(this)
  }


  handleSearch() {
    const result = this.state.result
    this.props.getUserRepos(result)
  }

  handleInput(event) {
    this.setState({
      result: event.target.value
    })
  }

  render() {
    const { repos, error } = this.props.Repos
    return (
      <div>
        <Container maxWidth='lg'>
          <div style={{ marginTop: 50, display: 'flex', justifyContent: 'center' }}>
            <TextField label="Username" type="search" variant="outlined" style={{ width: '90%' }} onChange={this.handleInput}/>
            <Button variant="contained" onClick={this.handleSearch} color="primary" style={{ textTransform: 'none', marginLeft: 5 }}>
              Search
            </Button>
          </div>
        </Container>

        <Container maxWidth='lg' style={{ marginTop: 20, display: 'flex', justifyContent: 'center' }}>
          <Card variant="outlined" style={{ width: '97%' }}>
            <CardContent>
              {!repos ? <p>This user does not have a repo</p> :
              repos.map((data, index) => {
                return (
                  <Typography>
                    <a href={data.html_url} style={{ textDecoration: 'none', color: 'black' }}> {data.name} </a>
                  </Typography>
                )
              })}
            </CardContent>
          </Card>
        </Container>
      </div>
    )
  }
}

const mapStateToProps = (state) => {
  return {
    Repos: state.Repos
  }
}

const mapDispatchToProps = dispatch => {
  return {
    getUserRepos: (user) => {
      dispatch(getUserRepos(user))
    }
  }
}


export default connect(mapStateToProps, mapDispatchToProps)(App)
