import { GET_USER_REPOS } from '../config/Constants'

const initialState = {
  repos: [],
  isLoading: false,
  error: false
}

export const Repos = (state = initialState, action) => {
  switch (action.type) {
    case `${GET_USER_REPOS}_PENDING`:
      return {
        ...state,
        isLoading: true,
      }
    case `${GET_USER_REPOS}_FULFILLED`:
      return {
        ...state,
        repos: action.payload.data,
        isLoading: false
      }
    case `${GET_USER_REPOS}_REJECTED`:
      return {
        error: true,
        isLoading: false
      }

    default:
      return state;
  }
}

